{
  "title": "Introduction to Python for Game Development",
  "description": "This course is designed for beginners who want to learn Python with a focus on game development. Participants will gain foundational knowledge of Python programming while exploring web development concepts applicable to game creation.",
  "modules": [
    {
      "id": "module1",
      "title": "Getting Started with Python",
      "description": "Learn the basics of Python programming, including installation, syntax, data types, and control structures. This module sets the foundation for further exploration in game development."
    },
    {
      "id": "module2",
      "title": "Introduction to Game Development Concepts",
      "description": "Explore the fundamental concepts of game development, including game design principles, graphics, and user interaction. This module will introduce you to libraries and frameworks used in Python for game development."
    },
    {
      "id": "module3",
      "title": "Building Your First Game",
      "description": "Apply your Python skills to create a simple game. This hands-on module will guide you through the process of designing, coding, and testing a basic game using Python."
    },
    {
      "id": "module4",
      "title": "Web Development for Games",
      "description": "Learn how to integrate web development skills with your Python knowledge to enhance your games. This module covers web frameworks, APIs, and how to deploy your game online."
    }
  ]
}
